using EventTuple = std::tuple<std::vector<int>, std::vector<int>, std::vector<double>, std::vector<int>>;

std::vector<EventTuple> create_window(const EventTuple& event, const std::string& stacking_type = "SBN") {
    const auto& [x, y, t, p] = event;

    std::vector<EventTuple> windows;
    int num_of_events = x.size() / 3;  
    windows.reserve(1 + 3 + 3); // Allocate memory for 7 windows in total
    windows.push_back(event);

