            std::vector<double> tmp_t(t.begin() + i * num_of_events, t.begin() + (i + 1) * num_of_events);
            std::vector<int> tmp_p(p.begin() + i * num_of_events, p.begin() + (i + 1) * num_of_events);
            windows.emplace_back(std::move(tmp_x), std::move(tmp_y), std::move(tmp_t), std::move(tmp_p));
        }

        int offset = num_of_events;
        for (int i = 0; i < 3; i++) {
